			if (cpu0_mem_wstrb[0]) assert(cpu0_mem_wdata[ 7: 0] == cpu1_mem_wdata[ 7: 0]);
		end
		if (trace_balance == 3'b010) begin
			assert(trace_buffer_cpu0 == trace_buffer_cpu1);
		end
	end

	picorv32 #(
		.ENABLE_COUNTERS(0),
		.REGS_INIT_ZERO(1),
		.COMPRESSED_ISA(1),
		.ENABLE_TRACE(1),

		.TWO_STAGE_SHIFT(0),
		.ENABLE_PCPI(1)
	) cpu0 (
