// new

function uvm_reg_field::new(string name = "uvm_reg_field");
   super.new(name);
endfunction: new


// configure

function void uvm_reg_field::configure(uvm_reg        parent,
                                       int unsigned   size,
                                       int unsigned   lsb_pos,
                                       string         access,
                                       bit            volatile,
                                       uvm_reg_data_t reset,
                                       bit            has_reset,
                                       bit            is_rand,
                                       bit            individually_accessible); 
   m_parent = parent;
   if (size == 0) begin
     `uvm_error("RegModel",
     $sformatf("Field \"%s\" cannot have 0 bits", get_full_name()))
     size = 1;
   end

   m_size      = size;
   m_volatile  = volatile;
   m_access    = access.toupper();
   m_lsb       = lsb_pos;
   m_cover_on  = UVM_NO_COVERAGE;
   m_written   = 0;
   m_check     = volatile ? UVM_NO_CHECK : UVM_CHECK;
   m_individually_accessible = individually_accessible;

   if (has_reset) begin

     set_reset(reset);
   end


   m_parent.add_field(this);

   if (!m_policy_names.exists(m_access)) begin
     `uvm_error("RegModel", {"Access policy '",access,
     "' for field '",get_full_name(),"' is not defined. Setting to RW"})
     m_access = "RW";
   end

   if (size > m_max_size) begin

     m_max_size = size;
   end


   // Ignore is_rand if the field is known not to be writeable
   // i.e. not "RW", "WRC", "WRS", "WO", "W1", "WO1"
   case (access)
     "RO", "RC", "RS", "WC", "WS",
     "W1C", "W1S", "W1T", "W0C", "W0S", "W0T",
     "W1SRC", "W1CRS", "W0SRC", "W0CRS", "WSRC", "WCRS",
     "WOC", "WOS": begin
       is_rand = 0;
     end

   endcase

   if (!is_rand) begin

     set_rand_mode(0);
   end


endfunction: configure


