function void uvm_mem::Xlock_modelX();
   m_locked = 1;
endfunction: Xlock_modelX


// get_full_name

function string uvm_mem::get_full_name();
   if (m_parent == null) begin

     return get_name();
   end


   return {m_parent.get_full_name(), ".", get_name()};

endfunction: get_full_name


