   local static function uvm_reg_read_only_cbs get();
      if (m_me == null) begin
        m_me = new;
      end

      return m_me;
   endfunction



   // @uvm-ieee 1800.2-2020 auto 18.11.4.2.2
   static function void add(uvm_reg rg);
      uvm_reg_field flds[$];

      uvm_reg_cb::add(rg, get());
      rg.get_fields(flds);
      foreach (flds[i]) begin
        uvm_reg_field_cb::add(flds[i], get());
      end
   endfunction



   // @uvm-ieee 1800.2-2020 auto 18.11.4.2.3
   static function void remove(uvm_reg rg);
      uvm_reg_cb_iter cbs = new(rg);
      uvm_reg_field flds[$];

      void'(cbs.first());
      while (cbs.get_cb() != get()) begin
        if (cbs.get_cb() == null) begin

          return;
        end

        void'(cbs.next());
      end
      uvm_reg_cb::delete(rg, get());
      rg.get_fields(flds);
      foreach (flds[i]) begin
        uvm_reg_field_cb::delete(flds[i], get());
      end
   endfunction
