                     string filename = "",
                     int line = 0,
                        string context_name = "",
                     bit report_enabled_checked = 0);

    this.uvm_report(UVM_INFO, id, message, verbosity, filename, line,
                    context_name, report_enabled_checked);
  endfunction

  // Function -- NODOCS -- uvm_report_warning

