    super.new(name);
  endfunction

  // Function -- NODOCS -- get_global_pool
  //
  // Returns the singleton global pool for the item type, T. 
  //
  // This allows items to be shared amongst components throughout the
  // verification environment.

  // @uvm-ieee 1800.2-2020 auto 10.4.1.2.2
  // @uvm-ieee 1800.2-2020 auto 10.4.2.2.2
  static function this_type get_global_pool ();
    if (m_global_pool==null)
      begin
        m_global_pool = new("global_pool");
      end

    return m_global_pool;
  endfunction


  // Function -- NODOCS -- get_global
  //
  // Returns the specified item instance from the global item pool. 

  // @uvm-ieee 1800.2-2020 auto 10.4.1.2.3
  // @uvm-ieee 1800.2-2020 auto 10.4.2.2.3
  static function T get_global (string key);
    this_type gpool;
    gpool = get_global_pool(); 
    return gpool.get(key);
  endfunction


  // Function -- NODOCS -- get
  //
  // Returns the object item at the given string ~key~.
  //
  // If no item exists by the given ~key~, a new item is created for that key
  // and returned.

  // @uvm-ieee 1800.2-2020 auto 10.4.1.2.4
  // @uvm-ieee 1800.2-2020 auto 10.4.2.2.4
  virtual function T get (string key);
    if (!pool.exists(key))
      begin
        pool[key] = new (key);
      end

    return pool[key];
  endfunction


  // Function -- NODOCS -- delete
  //
  // Removes the item with the given string ~key~ from the pool.

  virtual function void delete (string key);
    if (!exists(key)) 
      begin
        uvm_report_warning("POOLDEL",
        $sformatf("delete: key '%s' doesn't exist", key));
        return;
      end
    pool.delete(key);
  endfunction


  // Function- do_print

  virtual function void do_print (uvm_printer printer);
    string key;
    printer.print_array_header("pool",pool.num(),"aa_object_string");
    if (pool.first(key))
      begin
        do
        begin
          printer.print_object({"[",key,"]"}, pool[key],"[");
        end

        while (pool.next(key));
      end

    printer.print_array_footer();
  endfunction

