`define UVM_PH_TRACE(ID,MSG,PH,VERB) \
  if (uvm_phase::m_phase_trace) \
   `uvm_info(ID, {$sformatf("Phase '%0s' (id=%0d) ", \
       PH.get_full_name(), PH.get_inst_id()),MSG}, VERB)

