  virtual function void accept(STRUCTURE s, VISITOR v,uvm_structure_proxy#(STRUCTURE) p, bit invoke_begin_end=1);
    STRUCTURE c[$];

    if(invoke_begin_end)
      begin
        v.begin_v();
      end


    p.get_immediate_children(s, c);
    foreach(c[idx])
      begin
