function string uvm_component::massage_scope(string scope);

  // uvm_top
  if(scope == "") begin

    return "^$";
  end


  if(scope == "*") begin

    return {get_full_name(), ".*"};
  end


  // absolute path to the top-level test
  if(scope == "uvm_test_top") begin

    return "uvm_test_top";
  end


  // absolute path to uvm_root
  if(scope[0] == ".") begin

    return {get_full_name(), scope};
  end


  return {get_full_name(), ".", scope};

endfunction

